                new StatusUpdate { Description = "Arrived at sorting center", Location = "Chicago, IL", Timestamp = DateTime.Today.AddDays(-1).AddHours(14) },
                new StatusUpdate { Description = "In transit to destination", Location = "Chicago, IL", Timestamp = DateTime.Today.AddHours(8) },
            ]
        },
        ["PKG-002"] = new Shipment
        {
            TrackingNumber = "PKG-002",
            Status = "Delivered",
            Location = "San Francisco, CA",
            EstimatedDelivery = DateTime.Today.AddDays(-1),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Location = "Seattle, WA", Timestamp = DateTime.Today.AddDays(-5) },
                new StatusUpdate { Description = "In transit", Location = "Portland, OR", Timestamp = DateTime.Today.AddDays(-3) },
                new StatusUpdate { Description = "Out for delivery", Location = "San Francisco, CA", Timestamp = DateTime.Today.AddDays(-1).AddHours(9) },
                new StatusUpdate { Description = "Delivered — left at front door", Location = "San Francisco, CA", Timestamp = DateTime.Today.AddDays(-1).AddHours(14) },
            ]
        },
        ["PKG-003"] = new Shipment
        {
            TrackingNumber = "PKG-003",
            Status = "Processing",
            Location = "Dallas, TX",
            EstimatedDelivery = DateTime.Today.AddDays(5),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Label created", Location = "Dallas, TX", Timestamp = DateTime.Today.AddHours(-2) },
